var vendors = [];
var editingId = null;
var activeState = true;
function formatDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function isExpiringSoon(d) {
  if (!d) return false;
  return (new Date(d) - new Date()) / (1000 * 60 * 60 * 24) < 90;
}
function updateToggleUI() {
  var btn = document.getElementById('f_active_toggle');
  var lbl = document.getElementById('f_active_label');
  if (!btn) return;
  btn.className = 'toggle ' + (activeState ? 'on' : 'off');
  lbl.textContent = activeState ? 'Active' : 'Inactive';
}
function render(model) {
  vendors = model.vendors || [];
  var tbody = document.getElementById('table_body');
  if (!tbody) return;
  if (!vendors.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty">No vendors yet — add one to get started</td></tr>';
    return;
  }
  tbody.innerHTML = vendors.map(function (v, i) {
    var warn = isExpiringSoon(v.permit_expiry);
    var activeBadge = v.active ? '<span class="active-badge active-yes">Active</span>' : '<span class="active-badge active-no">Inactive</span>';
    return '<tr>' + '<td><strong>' + (v.name || '—') + '</strong></td>' + '<td>' + (v.permit_number || '—') + '</td>' + '<td class="' + (warn ? 'expiry-warn' : '') + '">' + formatDate(v.permit_expiry) + (warn ? ' ⚠' : '') + '</td>' + '<td>' + formatDate(v.review_date) + '</td>' + '<td>' + (v.contact_name || '—') + (v.contact_email ? '<br><span style="color:#6b7280;font-size:11px">' + v.contact_email + '</span>' : '') + '</td>' + '<td>' + activeBadge + '</td>' + '<td style="display:flex;gap:6px">' + '<button class="btn-sm btn-edit" onclick="window.editVendor(' + i + ')">Edit</button>' + '<button class="btn-sm btn-delete" onclick="window.deleteVendor(' + i + ')">Delete</button>' + '</td>' + '</tr>';
  }).join('');
}
window.openForm = function () {
  editingId = null;
  activeState = true;
  document.getElementById('form_title').textContent = 'Add Vendor';
  ['f_name', 'f_permit', 'f_permit_expiry', 'f_review_date', 'f_contact_name', 'f_contact_phone', 'f_contact_email', 'f_address', 'f_notes'].forEach(function (id) {
    document.getElementById(id).value = '';
  });
  updateToggleUI();
  document.getElementById('form_panel').classList.add('open');
};
window.closeForm = function () {
  document.getElementById('form_panel').classList.remove('open');
};
window.toggleActive = function () {
  activeState = !activeState;
  updateToggleUI();
};
window.editVendor = function (i) {
  var v = vendors[i];
  if (!v) return;
  editingId = v.vendor_id;
  activeState = v.active;
  document.getElementById('form_title').textContent = 'Edit Vendor';
  document.getElementById('f_name').value = v.name || '';
  document.getElementById('f_permit').value = v.permit_number || '';
  document.getElementById('f_permit_expiry').value = v.permit_expiry ? v.permit_expiry.split('T')[0] : '';
  document.getElementById('f_review_date').value = v.review_date ? v.review_date.split('T')[0] : '';
  document.getElementById('f_contact_name').value = v.contact_name || '';
  document.getElementById('f_contact_phone').value = v.contact_phone || '';
  document.getElementById('f_contact_email').value = v.contact_email || '';
  document.getElementById('f_address').value = v.address || '';
  document.getElementById('f_notes').value = v.notes || '';
  updateToggleUI();
  document.getElementById('form_panel').classList.add('open');
};
window.deleteVendor = function (i) {
  var v = vendors[i];
  if (!v) return;
  appsmith.updateModel({
    vendor_id: v.vendor_id
  });
  appsmith.triggerEvent('onDeleteVendor');
};
window.saveVendor = function () {
  appsmith.updateModel({
    vendor_id: editingId,
    vendor_name: document.getElementById('f_name').value,
    vendor_permit: document.getElementById('f_permit').value,
    vendor_permit_expiry: document.getElementById('f_permit_expiry').value || null,
    vendor_review_date: document.getElementById('f_review_date').value || null,
    vendor_contact_name: document.getElementById('f_contact_name').value,
    vendor_contact_phone: document.getElementById('f_contact_phone').value,
    vendor_contact_email: document.getElementById('f_contact_email').value,
    vendor_address: document.getElementById('f_address').value,
    vendor_notes: document.getElementById('f_notes').value,
    vendor_active: activeState,
    is_edit: editingId !== null
  });
  appsmith.triggerEvent('onSaveVendor');
  window.closeForm();
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

